// src/components/payment/Payment.jsx
import { useState, useEffect } from "react";
import './Payment.css';

// Simple location hook (minimal version)
export const useDeviceLocation = () => {
  const [location, setLocation] = useState({
    latitude: null,
    longitude: null
  });

  useEffect(() => {
    if (navigator.geolocation) {
      navigator.geolocation.getCurrentPosition(
        (position) => {
          setLocation({
            latitude: position.coords.latitude,
            longitude: position.coords.longitude
          });
        },
        () => {
          console.warn('Geolocation permission denied');
        } 
      );
    }
  }, []);

  return { location };
};

const AmountForm = ({ amount = 0, transportData, setSuccess, setError }) => {
  const [isLoading, setIsLoading] = useState(false);
  const [error, setErrorState] = useState("");
  const [success, setSuccessState] = useState("");
  const [isFrame, setIsFrame] = useState(false);
  const [keyGroup, setKeyGroup] = useState(null);
  const [showQR, setShowQR] = useState(false);
  const [paymentData, setPaymentData] = useState(null);

  // Auto-submit when amount is provided
  useEffect(() => {
    if (amount && amount >= 10 && amount <= 50000) {
      handleSubmit(amount);
    }
  }, [amount]);

  const handleSubmit = async (submitAmount) => {
    if (!submitAmount || submitAmount < 10 || submitAmount > 50000) {
      const errorMsg = "Amount must be between ₹10 and ₹50,000";
      setErrorState(errorMsg);
      if (setError) setError(errorMsg);
      return;
    }

    setIsLoading(true);
    setErrorState("");
    setSuccessState("");

    try {
      const token = "eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJfaWQiOiI2NzEwODhmZjM4ZGJhNzhhZDY2YjVmZWIiLCJwaG9uZU51bWJlciI6ODgxMDMwMDcyNCwiZW1haWwiOiJzeTI0MTUyN0BnbWFpbC5jb20iLCJyb2xlIjoiY2hhZ2Fuc0VtcGxveWVlMiIsImxvZ2luSWQiOiJmOGUzOWRhOC03MmQ2LTRmNTUtYWJlMC0xM2Q5YWIxMjJmZTkiLCJpYXQiOjE3NjkxNDM0NDUsImV4cCI6MTc3NjkxOTQ0NX0.Y8_yAqXxKhw7Hijfn5zJkHfWDHqijjRyxDom2XwqzFs";
      
      if (!token) {
        const errorMsg = "Authentication required. Please login.";
        setErrorState(errorMsg);
        if (setError) setError(errorMsg);
        setIsLoading(false);
        return;
      }

      console.log("Sending payment request with amount:", submitAmount);

      const response = await fetch(
        `https://chagans.com/payment/addMoneyTen`,
        {
          method: "POST",
          headers: {
            "Content-Type": "application/json",
            "Authorization": `Bearer ${token}`,
            "Accept": "application/json"
          },
          body: JSON.stringify({
            amount: submitAmount, 
            transportData: {
              ...transportData,
              trackingId: `TRK${Math.floor(100000 + Math.random() * 900000)}`,
            },
            mobile: "7983920962",
            apiType: "API",
          }),
        }
      );

      console.log("Response status:", response.status);
      
      if (!response.ok) {
        const errorText = await response.text();
        console.error("Error response:", errorText);
        throw new Error(`HTTP error! status: ${response.status}`);
      }

      const data = await response.json();
      console.log("Payment response data:", data);
      
      if (data.success) {
        // Don't call setSuccess here - that would trigger order placement
        // Instead, store the payment data and show QR code
        setPaymentData(data.data);
        setKeyGroup(data.data);
        setShowQR(true);
        setIsFrame(true);
        setSuccessState("Payment initiated! Please scan QR code to complete payment.");
        
        // Don't auto-submit form - we want to show QR code first
        // setTimeout(() => {
        //   const form = document.getElementById('payment-form');
        //   if (form) form.submit();
        // }, 500);
      } else {
        const errorMsg = data.message || "Payment failed. Please try again.";
        setErrorState(errorMsg);
        if (setError) setError(errorMsg);
      }
    } catch (err) {
      console.error('Full payment error:', err);
      
      let errorMsg = "Network error. Please check your connection.";
      if (err.message.includes('Failed to fetch')) {
        errorMsg = "Unable to connect to payment server.";
      } else if (err.message.includes('HTTP error')) {
        errorMsg = `Server error: ${err.message}`;
      }
      
      setErrorState(errorMsg);
      if (setError) setError(errorMsg);
    } finally {
      setIsLoading(false);
    }
  };

  // Function to handle payment completion
  const handlePaymentComplete = () => {
    // Now call setSuccess to trigger order placement
    if (setSuccess) {
      setSuccess("Payment completed successfully!");
    }
  };

  return (
    <div className="amount-form-container">
      {/* Hidden form for auto-submission - kept for reference */}
      {isFrame && keyGroup && (
        <form
          id="payment-form"
          action={keyGroup?.APIURL}
          method="POST"
          style={{ display: 'none' }}
        >
          {Object.entries(keyGroup)
            .filter(([key]) => key !== "APIURL")
            .filter(([key]) => key !== "mobile")
            .map(([key, value]) => (
              <input
                type="hidden"
                key={key}
                name={key.toUpperCase()}
                value={value}
              />
            ))}
        </form>
      )}

      {/* Status Display */}
      <div className="status-container">
        {error && (
          <div className="error-message">
            <svg className="error-icon" viewBox="0 0 24 24">
              <circle cx="12" cy="12" r="10" fill="#fee"/>
              <path d="M12 8v4M12 16h.01" stroke="#dc2626" strokeWidth="2" strokeLinecap="round"/>
            </svg>
            <div className="message-content">
              <h3>Payment Error</h3>
              <p>{error}</p>
            </div>
          </div>
        )}

        {success && !showQR && (
          <div className="success-message">
            <svg className="success-icon" viewBox="0 0 24 24">
              <circle cx="12" cy="12" r="10" fill="#d1fae5"/>
              <path d="M8 12L11 15L16 9" stroke="#059669" strokeWidth="2" strokeLinecap="round"/>
            </svg>
            <div className="message-content">
              <h3>Success!</h3>
              <p>{success}</p>
            </div>
          </div>
        )}

        {isLoading && (
          <div className="loading-indicator">
            <div className="spinner"></div>
            <p>Initializing payment...</p>
          </div>
        )}
      </div>

      {/* QR Code Display - Show when payment is initialized */}
      {showQR && paymentData && (
        <div className="qr-container">
          <h3>Scan QR Code to Pay</h3>
          <div className="amount-display" style={{marginBottom: '20px'}}>
            <div className="amount-value">₹{amount.toLocaleString('en-IN')}</div>
          </div>
          
          {/* QR Code Image - You'll need to generate this from paymentData */}
          <div className="qr-code">
            <img 
              src={`https://api.qrserver.com/v1/create-qr-code/?size=200x200&data=${encodeURIComponent(JSON.stringify(paymentData))}`}
              alt="Payment QR Code"
              style={{width: '200px', height: '200px'}}
            />
          </div>

          <div className="payment-details" style={{marginTop: '20px', textAlign: 'left'}}>
            <p><strong>Payment ID:</strong> {paymentData.PAY_ID}</p>
            <p><strong>Amount:</strong> ₹{parseInt(paymentData.AMOUNT)/100}</p>
            <p><strong>Status:</strong> <span style={{color: '#16a34a'}}>Pending</span></p>
          </div>

          <div className="payment-instructions" style={{
            background: '#f3f4f6',
            padding: '15px',
            borderRadius: '8px',
            marginTop: '20px'
          }}>
            <p style={{margin: '0 0 10px 0', fontWeight: 'bold'}}>📱 Instructions:</p>
            <ol style={{margin: '0', paddingLeft: '20px'}}>
              <li>Open any UPI app (GPay, PhonePe, PayTM)</li>
              <li>Scan this QR code</li>
              <li>Complete the payment</li>
              <li>Click "I've Completed Payment" below</li>
            </ol>
          </div>

          {/* Buttons */}
          <div style={{display: 'flex', gap: '10px', marginTop: '20px'}}>
            <button
              className="complete-payment-btn"
              onClick={handlePaymentComplete}
              style={{
                flex: 1,
                padding: '12px',
                background: '#16a34a',
                color: 'white',
                border: 'none',
                borderRadius: '8px',
                fontSize: '16px',
                fontWeight: '500',
                cursor: 'pointer'
              }}
            >
              ✅ I've Completed Payment
            </button>
            <button
              className="cancel-payment-btn"
              onClick={() => {
                setShowQR(false);
                setPaymentData(null);
                setErrorState("Payment cancelled");
                if (setError) setError("Payment cancelled");
              }}
              style={{
                padding: '12px 20px',
                background: '#6b7280',
                color: 'white',
                border: 'none',
                borderRadius: '8px',
                fontSize: '16px',
                cursor: 'pointer'
              }}
            >
              ✕ Cancel
            </button>
          </div>
        </div>
      )}

      {/* Amount Display - Show before payment is initialized */}
      {amount && !isLoading && !error && !success && !showQR && !isFrame && (
        <div className="amount-display">
          <div className="amount-label">Total Amount:</div>
          <div className="amount-value">₹{amount.toLocaleString('en-IN')}</div>
          <div className="amount-note">
            Initializing payment gateway...
          </div>
        </div>
      )}

      {/* Manual Retry Button */}
      {error && amount && !showQR && (
        <button
          className="retry-button"
          onClick={() => handleSubmit(amount)}
          disabled={isLoading}
        >
          {isLoading ? 'Retrying...' : 'Retry Payment'}
        </button>
      )}
    </div>
  );
};

export default AmountForm;
